func sessionHeatDotClass(heat string) string {
	switch heat {
	case "hot":
		return "st-session-dot st-session-dot-hot"
	case "warm":
		return "st-session-dot st-session-dot-warm"
	case "cold":
		return "st-session-dot st-session-dot-cold"
	default:
		return ""
	}
}

func sessionDetailDotClass(active bool, lastTS time.Time) string {
	if !active {
		return "inline-block w-1.5 h-1.5 rounded-full bg-base-content/20"
	}
	age := time.Since(lastTS)
	switch {
	case age <= 60*time.Second:
		return "st-session-dot st-session-dot-hot"
	case age <= 120*time.Second:
		return "st-session-dot st-session-dot-warm"
	default:
		return "st-session-dot st-session-dot-cold"
	}
}

func sessionDuration(first, last time.Time) string {
	if first.IsZero() || last.IsZero() {
		return "-"
	}
	d := last.Sub(first)
	switch {
	case d < time.Minute:
		return fmt.Sprintf("%ds", int(d.Seconds()))
	case d < time.Hour:
		return fmt.Sprintf("%dm", int(d.Minutes()))
	default:
		h := int(d.Hours())
		m := int(d.Minutes()) % 60
		if m == 0 {
			return fmt.Sprintf("%dh", h)
		}
		return fmt.Sprintf("%dh%dm", h, m)
	}
}

